using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that call external APIs via HttpClient.
/// </summary>
public class ApiTools
{
    [McpServerTool, Description("Fetches a post by ID from the JSONPlaceholder API.")]
    public static async Task<string> GetPost(
        IHttpClientFactory httpClientFactory,
        [Description("The numeric ID of the post to retrieve.")] int id,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");
        using var response = await client.GetAsync($"/posts/{id}", cancellationToken);

        response.EnsureSuccessStatusCode();

        var post = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return post.ToString();
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP prompt templates for summarization tasks.
/// </summary>
public class SummarizationPrompts
{
    [McpServerPrompt, Description("Generates a prompt that asks an LLM to summarize the given text.")]
    public static IEnumerable<ChatMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional desired summary style (e.g. 'bullet-points', 'one-paragraph'). Defaults to 'concise'.")] string style = "concise")
    {
        yield return new ChatMessage(
            ChatRole.User,
            $"""
            Summarize the following text in a {style} style.

            ---
            {text}
            ---
            """);
    }
}

